// Pull in the NOAA observation, the Open-Meteo UV response (this node's input),
// and the shared Config values.
const obsRoot = $('Get NOAA Observation').first().json;
const obs = (obsRoot && obsRoot.properties) ? obsRoot.properties : {};
const uvData = $input.first().json;
const config = $('Config').first().json;

// ---- Raw NOAA readings (do not alter) ----
const tempC = (obs.temperature && obs.temperature.value != null) ? obs.temperature.value : null;
const tempF = tempC !== null ? (tempC * 9 / 5 + 32) : null;

const rh = (obs.relativeHumidity && obs.relativeHumidity.value != null) ? obs.relativeHumidity.value : null;

const windKmh = (obs.windSpeed && obs.windSpeed.value != null) ? obs.windSpeed.value : null;
const windMph = windKmh !== null ? (windKmh * 0.621371) : null;

const condition = obs.textDescription || 'Unknown';

// ---- NOAA Heat Index (Rothfusz regression), used when T >= 80F and humidity is available ----
function calcHeatIndex(T, RH) {
  if (T === null || RH === null || T < 80) return null;
  let HI = -42.379 + 2.04901523 * T + 10.14333127 * RH - 0.22475541 * T * RH
    - 0.00683783 * T * T - 0.05481717 * RH * RH + 0.00122874 * T * T * RH
    + 0.00085282 * T * RH * RH - 0.00000199 * T * T * RH * RH;
  if (RH < 13 && T >= 80 && T <= 112) {
    HI -= ((13 - RH) / 4) * Math.sqrt((17 - Math.abs(T - 95)) / 17);
  } else if (RH > 85 && T >= 80 && T <= 87) {
    HI += ((RH - 85) / 10) * ((87 - T) / 5);
  }
  return Math.round(HI * 10) / 10;
}

// ---- NWS Wind Chill (2001 formula), used when T <= 50F and wind >= 3 mph ----
function calcWindChill(T, V) {
  if (T === null || V === null || T > 50 || V < 3) return null;
  const WC = 35.74 + 0.6215 * T - 35.75 * Math.pow(V, 0.16) + 0.4275 * T * Math.pow(V, 0.16);
  return Math.round(WC * 10) / 10;
}

const heatIndex = calcHeatIndex(tempF, rh);
const windChill = calcWindChill(tempF, windMph);

// ---- Feels Like: Heat Index > Wind Chill > Actual Temp ----
let feelsLike;
if (heatIndex !== null) feelsLike = heatIndex;
else if (windChill !== null) feelsLike = windChill;
else feelsLike = tempF;

const riskValue = feelsLike !== null ? Math.round(feelsLike * 10) / 10 : null;

// ---- Zone ----
let zone = 'UNKNOWN';
if (riskValue !== null) {
  if (riskValue <= 90) zone = 'GREEN';
  else if (riskValue <= 103) zone = 'YELLOW';
  else if (riskValue <= 115) zone = 'RED';
  else zone = 'BLACK';
}

// ---- UV (Open-Meteo, supplemental only) ----
const uv = (uvData && uvData.current && uvData.current.uv_index != null) ? uvData.current.uv_index : null;
function uvCategory(v) {
  if (v === null) return 'Unknown';
  if (v < 3) return 'Low';
  if (v < 6) return 'Moderate';
  if (v < 8) return 'High';
  if (v < 11) return 'Very High';
  return 'Extreme';
}

return [{
  json: {
    temperature: tempF !== null ? Math.round(tempF * 10) / 10 : null,
    feelsLike: feelsLike !== null ? Math.round(feelsLike * 10) / 10 : null,
    heatIndex,
    windChill,
    humidity: rh !== null ? Math.round(rh * 10) / 10 : null,
    wind: windMph !== null ? Math.round(windMph * 10) / 10 : null,
    condition,
    uv,
    uvCategory: uvCategory(uv),
    riskValue,
    zone,
    updated: new Date().toISOString(),
    firebaseBaseUrl: config.firebaseBaseUrl,
    firebaseAuth: config.firebaseAuth,
    resendApiKey: config.resendApiKey,
    fromEmail: config.fromEmail,
    recipient1: config.recipient1,
    recipient2: config.recipient2
  }
}];

// $input here is the raw previous-zone value read from Firebase (a plain string, or null on first run).
const current = $('Calculate Feels Like & Risk').first().json;
let previousZone = $input.first().json;

// The RTDB REST API returns the raw leaf value. If it ever comes back as an
// object (e.g. someone wrote {zone: 'GREEN'} at this path), unwrap it safely.
if (previousZone && typeof previousZone === 'object') {
  previousZone = previousZone.zone || null;
}
if (typeof previousZone !== 'string') previousZone = null;

// Only treat it as a "change" if we had a real previous value that differs.
// This avoids firing a false alert on the very first run.
const zoneChanged = previousZone !== null && previousZone !== current.zone;

return [{
  json: {
    ...current,
    previousZone: previousZone || current.zone,
    zoneChanged
  }
}];
